  1→import { getColumnAutoLabel } from '@/domain/columnLabels';
  2→import { getBeamRenderData } from '@/geometry/beamGeometry';
  3→import { columnCenter } from '@/geometry/columnGeometry';
  4→import { add, perpendicular, scale } from '@/geometry/point';
  5→import { doorOutlineOnWall, wallDirection, windowOutlineOnWall } from '@/geometry/wallGeometry';
  6→import { formatAreaLabel } from './format';
  7→import { ANNOTATION_SEMANTIC_ROLES, ANNOTATION_TRUST_LEVELS } from './policy';
  8→
  9→function formatRoomArea(room) {
 10→  return formatAreaLabel(room.area);
 11→}
 12→
 13→function createTag(id, textLines, position, options = {}) {
 14→  const lines = textLines.filter(Boolean);
 15→  if (!lines.length) return null;
 16→
 17→  return {
 18→    id,
 19→    type: 'tag',
 20→    trustLevel: options.trustLevel ?? ANNOTATION_TRUST_LEVELS.INFORMATIONAL,
 21→    semanticRole: options.semanticRole ?? ANNOTATION_SEMANTIC_ROLES.LABEL,
 22→    sourceType: options.sourceType ?? null,
 23→    sourceId: options.sourceId ?? null,
 24→    position,
 25→    angle: options.angle ?? 0,
 26→    textLines: lines,
 27→    textAnchor: options.textAnchor ?? 'middle',
 28→    priority: options.priority ?? 0,
 29→  };
 30→}
 31→
 32→function buildColumnTags(columns = []) {
 33→  return columns
 34→    .map((column, index) => createTag(
 35→      `column-tag-${column.id}`,
 36→      [column.name?.trim() || getColumnAutoLabel(column, columns) || `C${index + 1}`],
 37→      columnCenter(column),
 38→      { sourceType: 'column', sourceId: column.id, priority: 1 }
 39→    ))
 40→    .filter(Boolean);
 41→}
 42→
 43→function buildBeamTags(beams = [], columns = []) {
 44→  return beams
 45→    .map((beam, index) => {
 46→      const renderData = getBeamRenderData(beam, columns || []);
 47→      if (!renderData) return null;
 48→      return createTag(
 49→        `beam-tag-${beam.id}`,
 50→        [`B${index + 1}`],
 51→        renderData.midpoint,
 52→        { sourceType: 'beam', sourceId: beam.id, priority: 1 }
 53→      );
 54→    })
 55→    .filter(Boolean);
 56→}
 57→
 58→function buildRoomTags(rooms = []) {
 59→  return rooms
 60→    .map((room, index) => createTag(
 61→      `room-tag-${room.id}`,
 62→      [room.name?.trim() || `R${index + 1}`, formatRoomArea(room)],
 63→      room.labelPosition,
 64→      { sourceType: 'room', sourceId: room.id, priority: 3 }
 65→    ))
 66→    .filter(Boolean);
 67→}
 68→
 69→function buildDoorTags(doors = [], walls = []) {
 70→  return doors
 71→    .map((door, index) => {
 72→      const wall = walls.find((entry) => entry.id === door.wallId);
 73→      if (!wall) return null;
 74→      const info = doorOutlineOnWall(wall, door);
 75→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 76→      return createTag(
 77→        `door-tag-${door.id}`,
 78→        [`D${index + 1}`],
 79→        add(info.center, offset),
 80→        { sourceType: 'door', sourceId: door.id, priority: 0 }
 81→      );
 82→    })
 83→    .filter(Boolean);
 84→}
 85→
 86→function buildWindowTags(windows = [], walls = []) {
 87→  return windows
 88→    .map((windowItem, index) => {
 89→      const wall = walls.find((entry) => entry.id === windowItem.wallId);
 90→      if (!wall) return null;
 91→      const info = windowOutlineOnWall(wall, windowItem);
 92→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 93→      return createTag(
 94→        `window-tag-${windowItem.id}`,
 95→        [`W${index + 1}`],
 96→        add(info.center, offset),
 97→        { sourceType: 'window', sourceId: windowItem.id, priority: 0 }
 98→      );
 99→    })
100→    .filter(Boolean);
101→}
102→
103→function estimateTagBounds(tag) {
104→  const fontSize = tag.sourceType === 'room' ? 150 : 120;
105→  const lineHeight = tag.sourceType === 'room' ? 166 : 150;
106→  const maxLineLength = Math.max(...tag.textLines.map((line) => line.length), 1);
107→  const width = Math.max(220, maxLineLength * fontSize * 0.62);
108→  const height = Math.max(lineHeight, tag.textLines.length * lineHeight);
109→
110→  return {
111→    left: tag.position.x - width / 2,
112→    right: tag.position.x + width / 2,
113→    top: tag.position.y - height / 2,
114→    bottom: tag.position.y + height / 2,
115→  };
116→}
117→
118→function intersects(a, b) {
119→  return a.left < b.right && a.right > b.left && a.top < b.bottom && a.bottom > b.top;
120→}
121→
122→function applyCollisionOffsets(tags = []) {
123→  const placed = [];
124→  const offsets = [
125→    { x: 0, y: 0 },
126→    { x: 0, y: -180 },
127→    { x: 0, y: 180 },
128→    { x: 180, y: 0 },
129→    { x: -180, y: 0 },
130→    { x: 160, y: -130 },
131→    { x: -160, y: -130 },
132→  ];
133→
134→  return [...tags]
135→    .sort((a, b) => b.priority - a.priority)
136→    .map((tag) => {
137→      for (const offset of offsets) {
138→        const candidate = {
139→          ...tag,
140→          position: {
141→            x: tag.position.x + offset.x,
142→            y: tag.position.y + offset.y,
143→          },
144→        };
145→        const candidateBounds = estimateTagBounds(candidate);
146→        if (!placed.some((placedTag) => intersects(candidateBounds, placedTag.bounds))) {
147→          placed.push({ bounds: candidateBounds });
148→          return candidate;
149→        }
150→      }
151→
152→      const bounds = estimateTagBounds(tag);
153→      placed.push({ bounds });
154→      return tag;
155→    });
156→}
157→
158→export function buildAnnotationTags(floor) {
159→  return applyCollisionOffsets([
160→    ...buildColumnTags(floor.columns || []),
161→    ...buildBeamTags(floor.beams || [], floor.columns || []),
162→    ...buildRoomTags(floor.rooms || []),
163→    ...buildDoorTags(floor.doors || [], floor.walls || []),
164→    ...buildWindowTags(floor.windows || [], floor.walls || []),
165→  ]);
166→}
