 615→function createDetailTag(id, textLines, position, options = {}) {
 616→  const lines = (textLines || []).filter(Boolean);
 617→  if (!lines.length) return null;
 618→
 619→  return {
 620→    id,
 621→    type: 'tag',
 622→    trustLevel: options.trustLevel ?? ANNOTATION_TRUST_LEVELS.INFORMATIONAL,
 623→    semanticRole: options.semanticRole ?? ANNOTATION_SEMANTIC_ROLES.MEASUREMENT,
 624→    sourceType: options.sourceType ?? 'truss_detail',
 625→    sourceId: options.sourceId ?? null,
 626→    position,
 627→    angle: options.angle ?? 0,
 628→    textLines: lines,
 629→    textAnchor: options.textAnchor ?? 'middle',
 630→    priority: options.priority ?? 0,
 631→    measurementMeta: Number.isFinite(options.measurementValue)
 632→      ? createMeasurementMetadata(options.measurementValue)
 633→      : null,
 634→    fontSize: options.fontSize ?? DETAIL_TAG_FONT_SIZE,
 635→    lineHeight: options.lineHeight ?? DETAIL_TAG_LINE_HEIGHT,
 636→    mask: options.mask ?? true,
 637→    maskPaddingX: options.maskPaddingX ?? DETAIL_TAG_MASK_PADDING_X,
 638→    maskPaddingY: options.maskPaddingY ?? DETAIL_TAG_MASK_PADDING_Y,
 639→    leaderLine: options.leaderLine ?? null,
 640→  };
 641→}
 642→
 643→function normalizeTagAngle(angleDeg = 0) {
 644→  return angleDeg > 90 || angleDeg < -90 ? angleDeg + 180 : angleDeg;
 645→}
 646→
 647→function estimateTextWidth(text, fontSize) {
 648→  return Math.max(fontSize * 1.2, String(text || '').length * fontSize * 0.58);
 649→}
 650→
 651→function estimateDimensionBounds(figure) {
 652→  if (!figure) return null;
 653→
 654→  const points = [
 655→    figure.lineStart,
 656→    figure.lineEnd,
 657→    ...figure.extensionLines.flatMap((line) => [line.start, line.end]),
 658→    ...figure.arrowheads.flatMap((arrow) => [arrow.left, arrow.tip, arrow.right]),
 659→  ].filter(Boolean);
 660→  const fontSize = DRAWING_GRAPHICS.annotation.textSize;
 661→  const width = estimateTextWidth(figure.text?.value, fontSize) + DRAWING_GRAPHICS.annotation.textMaskPaddingX;
 662→  const height = fontSize + DRAWING_GRAPHICS.annotation.textMaskPaddingY;
 663→  const textPosition = figure.text?.position || { x: 0, y: 0 };
 664→  const textRadius = Math.sqrt((width * width) + (height * height)) / 2;
 665→
 666→  points.push(
 667→    { x: textPosition.x - textRadius, y: textPosition.y - textRadius },
 668→    { x: textPosition.x + textRadius, y: textPosition.y + textRadius }
 669→  );
 670→
 671→  return {
 672→    minX: Math.min(...points.map((point) => point.x)),
 673→    maxX: Math.max(...points.map((point) => point.x)),
 674→    minY: Math.min(...points.map((point) => point.y)),
 675→    maxY: Math.max(...points.map((point) => point.y)),
 676→  };
 677→}
 678→
 679→function estimateTagBounds(tag) {
 680→  if (!tag) return null;
 681→
 682→  const fontSize = Number(tag.fontSize || DETAIL_TAG_FONT_SIZE);
 683→  const lineHeight = Number(tag.lineHeight || DETAIL_TAG_LINE_HEIGHT);
 684→  const maskPaddingX = Number(tag.maskPaddingX ?? DETAIL_TAG_MASK_PADDING_X);
 685→  const maskPaddingY = Number(tag.maskPaddingY ?? DETAIL_TAG_MASK_PADDING_Y);
 686→  const maxLineLength = Math.max(...tag.textLines.map((line) => String(line || '').length), 1);
 687→  const width = (maxLineLength * fontSize * 0.58) + Math.max(maskPaddingX, fontSize * 0.5);
 688→  const height = Math.max(lineHeight, tag.textLines.length * lineHeight) + maskPaddingY;
 689→  const minX = tag.textAnchor === 'start'
 690→    ? tag.position.x
 691→    : (tag.textAnchor === 'end' ? tag.position.x - width : tag.position.x - (width / 2));
 692→  const maxX = tag.textAnchor === 'start'
 693→    ? tag.position.x + width
 694→    : (tag.textAnchor === 'end' ? tag.position.x : tag.position.x + (width / 2));
 695→  const minY = tag.position.y - (height / 2);
 696→  const maxY = tag.position.y + (height / 2);
 697→  const angle = Number(tag.angle || 0);
 698→  const corners = [
 699→    { x: minX, y: minY },
 700→    { x: maxX, y: minY },
 701→    { x: maxX, y: maxY },
 702→    { x: minX, y: maxY },
 703→  ].map((corner) => rotate(corner, tag.position, angle));
 704→
 705→  return {
 706→    minX: Math.min(...corners.map((point) => point.x)),
 707→    maxX: Math.max(...corners.map((point) => point.x)),
 708→    minY: Math.min(...corners.map((point) => point.y)),
 709→    maxY: Math.max(...corners.map((point) => point.y)),
 710→  };
 711→}
 712→
 713→function selectOutwardNormal(normal, midpoint, spanMidpoint) {
 714→  const preferred = midpoint.x < spanMidpoint
 715→    ? { x: -1, y: 0 }
 716→    : { x: 1, y: 0 };
 717→  const alignment = (normal.x * preferred.x) + (normal.y * preferred.y);
 718→
 719→  return alignment >= 0
 720→    ? normal
 721→    : { x: -normal.x, y: -normal.y };
 722→}
 723→
 724→function extendDetailBounds(detailBounds, dimensions = [], tags = []) {
 725→  const bounds = {
 726→    minX: detailBounds.minX,
 727→    maxX: detailBounds.maxX,
 728→    minY: -detailBounds.maxZ,
 729→    maxY: -detailBounds.minZ,
 730→  };
 731→
 732→  for (const figure of dimensions) {
 733→    const figureBounds = estimateDimensionBounds(figure);
 734→    if (!figureBounds) continue;
 735→    bounds.minX = Math.min(bounds.minX, figureBounds.minX);
 736→    bounds.maxX = Math.max(bounds.maxX, figureBounds.maxX);
 737→    bounds.minY = Math.min(bounds.minY, figureBounds.minY);
 738→    bounds.maxY = Math.max(bounds.maxY, figureBounds.maxY);
 739→  }
 740→
 741→  for (const tag of tags) {
 742→    const tagBounds = estimateTagBounds(tag);
 743→    if (!tagBounds) continue;
 744→    bounds.minX = Math.min(bounds.minX, tagBounds.minX);
 745→    bounds.maxX = Math.max(bounds.maxX, tagBounds.maxX);
 746→    bounds.minY = Math.min(bounds.minY, tagBounds.minY);
 747→    bounds.maxY = Math.max(bounds.maxY, tagBounds.maxY);
 748→  }
 749→
 750→  return {
 751→    minX: bounds.minX,
 752→    maxX: bounds.maxX,
 753→    minZ: -bounds.maxY,
 754→    maxZ: -bounds.minY,
 755→  };
 756→}
 757→
 758→function resolveDetailCrestPoint(roofOutline = []) {
 759→  if (!roofOutline.length) {
 760→    return { x: 0, z: 0 };
 761→  }
 762→
 763→  const maxZ = Math.max(...roofOutline.map((point) => point.z));
 764→  const crestPoints = roofOutline.filter((point) => Math.abs(point.z - maxZ) <= 1e-6);
 765→  const averageX = crestPoints.reduce((sum, point) => sum + point.x, 0) / Math.max(crestPoints.length, 1);
 766→
 767→  return {
 768→    x: averageX,
 769→    z: maxZ,
 770→  };
 771→}
 772→
 773→function buildTrussDetailDimensions(instanceGeometry) {
 774→  const metrics = instanceGeometry.metrics || {};
 775→  const roofOutline = instanceGeometry.roofOutline || [];
 776→  const bottomOutline = instanceGeometry.bottomOutline || [];
 777→  const ridge = resolveDetailCrestPoint(roofOutline);
 778→  const roofMaxX = Math.max(...roofOutline.map((point) => point.x), metrics.span || 0);
 779→  const startEaveX = roofOutline[0]?.x ?? 0;
 780→  const endEaveX = roofOutline[roofOutline.length - 1]?.x ?? (metrics.span || 0);
 781→  const dimensions = [];
 782→  const tags = [];
 783→
 784→  const spanDimension = createDimensionFigure({
 785→    id: `${instanceGeometry.instance.id}_detail_span`,
 786→    startPoint: createDetailPoint({ x: 0, z: 0 }),
 787→    endPoint: createDetailPoint({ x: metrics.span || 0, z: 0 }),
 788→    mode: 'horizontal',
 789→    offset: DETAIL_SPAN_OFFSET,
 790→    label: `Span ${formatMeasurement(metrics.span || 0)}`,
 791→    source: 'derived',
 792→    sourceType: 'truss_detail',
 793→    sourceId: instanceGeometry.instance.id,
 794→  });
 795→  if (spanDimension) dimensions.push(spanDimension);
 796→
 797→  const riseDimension = createDimensionFigure({
 798→    id: `${instanceGeometry.instance.id}_detail_rise`,
 799→    startPoint: createDetailPoint({ x: ridge.x, z: 0 }),
 800→    endPoint: createDetailPoint(ridge),
 801→    mode: 'vertical',
 802→    offset: (roofMaxX - ridge.x) + DETAIL_RISE_OUTSET,
 803→    label: `Rise ${formatMeasurement(metrics.rise || 0)}`,
 804→    source: 'derived',
 805→    sourceType: 'truss_detail',
 806→    sourceId: instanceGeometry.instance.id,
 807→  });
 808→  if (riseDimension) dimensions.push(riseDimension);
 809→
 810→  const startOverhang = createDimensionFigure({
 811→    id: `${instanceGeometry.instance.id}_detail_overhang_start`,
 812→    startPoint: createDetailPoint({ x: -Math.max(metrics.overhangStart || 0, 0), z: 0 }),
 813→    endPoint: createDetailPoint({ x: 0, z: 0 }),
 814→    mode: 'horizontal',
 815→    offset: DETAIL_OVERHANG_OFFSET,
 816→    label: `OH A ${formatMeasurement(metrics.overhangStart || 0)}`,
 817→    source: 'derived',
 818→    sourceType: 'truss_detail',
 819→    sourceId: instanceGeometry.instance.id,
 820→  });
 821→  if (startOverhang) dimensions.push(startOverhang);
 822→
 823→  const endOverhang = createDimensionFigure({
 824→    id: `${instanceGeometry.instance.id}_detail_overhang_end`,
 825→    startPoint: createDetailPoint({ x: metrics.span || 0, z: 0 }),
 826→    endPoint: createDetailPoint({ x: (metrics.span || 0) + Math.max(metrics.overhangEnd || 0, 0), z: 0 }),
 827→    mode: 'horizontal',
 828→    offset: DETAIL_OVERHANG_OFFSET,
 829→    label: `OH B ${formatMeasurement(metrics.overhangEnd || 0)}`,
 830→    source: 'derived',
 831→    sourceType: 'truss_detail',
 832→    sourceId: instanceGeometry.instance.id,
 833→  });
 834→  if (endOverhang) dimensions.push(endOverhang);
 835→
 836→  if (bottomOutline.length >= 2) {
 837→    bottomOutline.slice(0, -1).forEach((startPoint, index) => {
 838→      const endPoint = bottomOutline[index + 1];
 839→      const panelDimension = createDimensionFigure({
 840→        id: `${instanceGeometry.instance.id}_detail_panel_${index}`,
 841→        startPoint: createDetailPoint(startPoint),
 842→        endPoint: createDetailPoint(endPoint),
 843→        mode: 'horizontal',
 844→        offset: DETAIL_PANEL_OFFSET,
 845→        label: `P${index + 1} ${formatMeasurement(endPoint.x - startPoint.x)}`,
 846→        source: 'derived',
 847→        sourceType: 'truss_detail',
 848→        sourceId: instanceGeometry.instance.id,
 849→      });
 850→      if (panelDimension) dimensions.push(panelDimension);
 851→    });
 852→  }
 853→
 854→  const purlinGroups = new Map();
 855→  for (const attachment of instanceGeometry.purlinAttachments || []) {
 856→    const key = attachment.side || 'default';
 857→    if (!purlinGroups.has(key)) {
 858→      purlinGroups.set(key, []);
 859→    }
 860→    purlinGroups.get(key).push(attachment);
 861→  }
 862→  for (const [side, attachments] of purlinGroups.entries()) {
 863→    const sorted = [...attachments].sort((a, b) => (a.distanceAlong || 0) - (b.distanceAlong || 0));
 864→    if (!sorted.length) continue;
 865→    const purlinSideOffset = side === 'right' ? DETAIL_PURLIN_OFFSET : -DETAIL_PURLIN_OFFSET;
 866→    const purlinStartPoint = side === 'right'
 867→      ? (roofOutline[roofOutline.length - 1] || ridge)
 868→      : (roofOutline[0] || ridge);
 869→
 870→    const purlinStartDimension = createDimensionFigure({
 871→      id: `${instanceGeometry.instance.id}_detail_purlin_start_${side}`,
 872→      startPoint: createDetailPoint(purlinStartPoint),
 873→      endPoint: createDetailPoint(sorted[0].localPoint),
 874→      mode: 'aligned',
 875→      offset: side === 'right' ? DETAIL_PURLIN_START_OFFSET : -DETAIL_PURLIN_START_OFFSET,
 876→      label: `Purlin Start ${formatMeasurement(sorted[0].distanceAlong || 0)}`,
 877→      source: 'derived',
 878→      sourceType: 'truss_detail',
 879→      sourceId: instanceGeometry.instance.id,
 880→    });
 881→    if (purlinStartDimension) {
 882→      dimensions.push(purlinStartDimension);
 883→    }
 884→
 885→    if (sorted.length < 2) {
 886→      if (purlinStartDimension) break;
 887→      continue;
 888→    }
 889→
 890→    const purlinDimension = createDimensionFigure({
 891→      id: `${instanceGeometry.instance.id}_detail_purlin_${side}`,
 892→      startPoint: createDetailPoint(sorted[0].localPoint),
 893→      endPoint: createDetailPoint(sorted[1].localPoint),
 894→      mode: 'aligned',
 895→      offset: purlinSideOffset,
 896→      label: `Purlin ${formatMeasurement(sorted[1].distanceAlong - sorted[0].distanceAlong)}`,
 897→      source: 'derived',
 898→      sourceType: 'truss_detail',
 899→      sourceId: instanceGeometry.instance.id,
 900→    });
 901→    if (purlinDimension) {
 902→      dimensions.push(purlinDimension);
 903→      break;
 904→    }
 905→
 906→    if (purlinStartDimension) break;
 907→  }
 908→
 909→  tags.push(
 910→    createDetailTag(
 911→      `${instanceGeometry.instance.id}_detail_pitch`,
 912→      [`Pitch ${Number(metrics.pitch || 0).toFixed(1)}%`],
 913→      { x: ridge.x, y: -ridge.z - 220 },
 914→      { sourceId: instanceGeometry.instance.id }
 915→    ),
 916→    createDetailTag(
 917→      `${instanceGeometry.instance.id}_detail_bearing_start`,
 918→      ['Bearing A', formatMeasurement(metrics.bearingStart || 0)],
 919→      { x: startEaveX - DETAIL_TAG_OUTSET, y: -180 },
 920→      {
 921→        sourceId: instanceGeometry.instance.id,
 922→        textAnchor: 'end',
 923→        measurementValue: metrics.bearingStart || 0,
 924→      }
 925→    ),
 926→    createDetailTag(
 927→      `${instanceGeometry.instance.id}_detail_bearing_end`,
 928→      ['Bearing B', formatMeasurement(metrics.bearingEnd || 0)],
 929→      { x: endEaveX + DETAIL_TAG_OUTSET, y: -180 },
 930→      {
 931→        sourceId: instanceGeometry.instance.id,
 932→        textAnchor: 'start',
 933→        measurementValue: metrics.bearingEnd || 0,
 934→      }
 935→    )
 936→  );
 937→
 938→  return {
 939→    dimensions: dimensions.filter(Boolean),
 940→    tags: tags.filter(Boolean),
 941→  };
 942→}
 943→
 944→function buildTrussDetailWebTags(lineSegments, instanceGeometry) {
 945→  const spanMidpoint = (instanceGeometry?.metrics?.span || 0) / 2;
 946→  let webIndex = 0;
 947→
 948→  return lineSegments
 949→    .filter((segment) => segment.memberType === 'web' && segment.start && segment.end)
 950→    .map((segment) => {
 951→      webIndex += 1;
 952→
 953→      const start = createDetailPoint(segment.start);
 954→      const end = createDetailPoint(segment.end);
 955→      const dx = end.x - start.x;
 956→      const dy = end.y - start.y;
 957→      const length = Math.hypot(dx, dy);
 958→      if (length <= 1) return null;
 959→
 960→      const midpoint = {
 961→        x: (start.x + end.x) / 2,
 962→        y: (start.y + end.y) / 2,
 963→      };
 964→      let offset = { x: 0, y: 0 };
 965→
 966→      if (Math.abs(dx) <= 1e-6) {
 967→        offset = {
 968→          x: midpoint.x < spanMidpoint ? -DETAIL_WEB_TAG_OFFSET : DETAIL_WEB_TAG_OFFSET,
 969→          y: 0,
 970→        };
 971→      } else {
 972→        const normal = { x: -dy / length, y: dx / length };
 973→        const tangent = { x: dx / length, y: dy / length };
 974→        const outwardNormal = selectOutwardNormal(normal, midpoint, spanMidpoint);
 975→        const tangentShift = (webIndex % 2 === 0 ? 1 : -1) * DETAIL_WEB_TAG_TANGENT_SHIFT;
 976→        offset = {
 977→          x: (outwardNormal.x * DETAIL_WEB_TAG_OFFSET) + (tangent.x * tangentShift),
 978→          y: (outwardNormal.y * DETAIL_WEB_TAG_OFFSET) + (tangent.y * tangentShift),
 979→        };
 980→      }
 981→
 982→      return createDetailTag(
 983→        `${instanceGeometry.instance.id}_detail_web_${webIndex}`,
 984→        [`W${webIndex} ${formatMeasurement(length)}`],
